  await insertVWA(verse_id, "amn", 3, "croire/avoir la foi", { sense_chosen: "croire/avoir la foi", concept_chosen: "Foi/Adhésion", concepts: { "Foi/Adhésion": { status: "retenu", senses: ["croire|avoir la foi|croyant"], proof_ctx: "Āmanū : Form IV accompli 3MP de amn = croire, avoir la foi. La formule d'adresse yā ayyuhā alladhīna āmanū est récurrente dans le Coran.", axe1_verset: "Yā ayyuhā alladhīna āmanū lā tubṭilū ṣadaqātikum. L'adresse aux āmanū contraste avec lā yuʾminu (pos=19) — le verset oppose foi authentique et absence de foi. La foi est la condition de base de la générosité sincère.", axe2_voisins: "La foi (āmanū pos=3) et son absence (lā yuʾminu pos=19) forment le contraste central. Le croyant peut annuler ses aumônes par le mann et l'adhan — d'où l'adresse directe aux croyants.", axe3_sourate: "La formule yā ayyuhā alladhīna āmanū apparaît une quinzaine de fois dans al-Baqarah pour des commandements directs aux croyants. Elle marque l'urgence et la personnalisation.", axe4_coherence: "L'adresse aux croyants implique que le risque d'annuler ses aumônes concerne les croyants eux-mêmes, pas seulement les hypocrites. C'est une mise en garde interne à la communauté.", axe5_frequence: "La Form IV āmana/yuʾminu apparaît des centaines de fois dans le Coran. La formule d'adresse yā ayyuhā alladhīna āmanū est caractéristique du style coranique." }, "Sécurité/Confiance": { status: "probable", senses: ["sécurité|confiance|fidèle"], proof_ctx: "La racine amn porte fondamentalement le sens de sécurité. Dans ce verset, le sens dominant est la foi religieuse.", axe1_verset: "Āmanū désigne ici la foi religieuse en Dieu et au Jour dernier, non la confiance mondaine.", axe2_voisins: "La paire āmanū / lā yuʾminu bi-llāhi confirme que amn désigne la foi religieuse.", axe3_sourate: "Dans al-Baqarah, āmanū dans les formules d'adresse désigne toujours la foi religieuse.", axe4_coherence: "Le contraste foi/non-foi structure le verset autour du clivage théologique.", axe5_frequence: "Dans les formules d'adresse coraniques, āmanū désigne toujours la foi religieuse." } } });

  await insertVWA(verse_id, "btl", 5, "annuler/rendre nul", { sense_chosen: "annuler/rendre nul", concept_chosen: "Vanité/Nullité", concepts: { "Vanité/Nullité": { status: "retenu", senses: ["être vain|faux|nul"], proof_ctx: "Tubṭilū : Form IV impératif négatif 2MP de btl = annuler, rendre nul. La Form IV abṭala = invalider.", axe1_verset: "Lā tubṭilū ṣadaqātikum bi-l-manni wa-l-adhā : n'annulez pas vos aumônes par le reproche et la nuisance. La Form IV causative indique que c'est le croyant lui-même qui annule ses propres aumônes — acte délibéré et responsable.", axe2_voisins: "L'ibṭāl est le danger principal des sections 261-265 : la générosité peut être annulée par des comportements qui la suivent. Tubṭilū résume ce danger en un seul verbe fort.", axe3_sourate: "La Form IV abṭala s'applique à l'invalidation d'actes religieux dans al-Baqarah. L'aumône peut être invalidée comme tout autre acte si les conditions de validité ne sont pas remplies.", axe4_coherence: "Lā tubṭilū est grammaticalement fort : impératif négatif direct. Ce n'est pas une suggestion mais un commandement ferme reconnaissant la réalité du danger d'annulation.", axe5_frequence: "La racine btl dans ses formes d'annulation apparaît une quinzaine de fois dans le Coran dans des contextes d'invalidation d'actes ou de vérités." }, "Annulation": { status: "probable", senses: ["annuler|invalider"], proof_ctx: "La Form IV de btl est précisément le sens d'annuler/invalider — sens retenu. Le sens de vanité (sens 1) est le sens premier de la racine, l'annulation est la Form IV causative.", axe1_verset: "Tubṭilū est Form IV = rendre nul, invalider — c'est le sens retenu directement.", axe2_voisins: "L'annulation des aumônes par le mann et l'adhan est exactement ce que tubṭilū exprime.", axe3_sourate: "Dans al-Baqarah, abṭala désigne l'annulation d'actes religieux.", axe4_coherence: "Tubṭilū ṣadaqātikum = annulez vos aumônes — sens direct et clair.", axe5_frequence: "La Form IV tubṭilū est la forme standard d'annulation dans le Coran." } } });

  await insertVWA(verse_id, "sdq", 6, "vos aumônes", { sense_chosen: "vos aumônes", concept_chosen: "Don/Aumône", concepts: { "Don/Aumône": { status: "retenu", senses: ["aumône|dot"], proof_ctx: "Ṣadaqātikum : pluriel ṣadaqāt + suffixe possessif 2MP = vos aumônes.", axe1_verset: "Lā tubṭilū ṣadaqātikum : le possessif -kum (vos) rend l'injonction personnelle. Chaque croyant risque d'annuler ses propres aumônes par ses comportements.", axe2_voisins: "Ṣadaqātikum désigne l'ensemble des actes de générosité accumulés. L'annulation par le mann et l'adhan peut concerner n'importe laquelle de ces aumônes.", axe3_sourate: "Le pluriel ṣadaqāt dans la section 261-274 désigne la générosité comme pratique régulière. La mise en garde s'applique à toute la pratique généreuse.", axe4_coherence: "Ṣadaqātikum + bi-l-manni wa-l-adhā montre que même les aumônes sincèrement accomplies peuvent être annulées après coup.", axe5_frequence: "Ṣadaqāt dans la section 261-274 est le terme récurrent pour les aumônes volontaires des croyants." } } });

  await insertVWA(verse_id, "mn", 8, "le reproche/rappel blessant", { sense_chosen: "le reproche/rappel blessant", concept_chosen: "Reproche/Rappel", concepts: { "Reproche/Rappel": { status: "retenu", senses: ["reprocher un bienfait"], proof_ctx: "Al-manni : avec article défini = le reproche comme catégorie définie.", axe1_verset: "Bi-l-manni wa-l-adhā = par le reproche et la nuisance. Al-mann avec article établit un binôme défini de comportements annulateurs. Ce sont des catégories connues et condamnées.", axe2_voisins: "Al-mann revient de V262 à V264 comme terme technique de la générosité dégradée. La progression de mannan (V262, sans article) à al-mann (V264, avec article) montre une montée en généralité.", axe3_sourate: "Al-mann dans cette section est établi comme terme de référence pour une faute spécifique dans la pratique de la générosité — rappeler son bienfait de façon blessante.", axe4_coherence: "Al-mann + al-adhā forment le binôme complet des comportements annulateurs, couvrant la parole (mann) et l'acte (adhā).", axe5_frequence: "Al-mann dans ce sens de reproche apparaît 4 fois dans la section 261-264, établissant sa centralité comme terme de référence." }, "Bienfait/Don": { status: "probable", senses: ["accorder un bienfait|donner|faveur"], proof_ctx: "Mann peut désigner le bienfait lui-même, mais dans ce contexte grammatical (après tubṭilū), al-mann est le comportement annulateur.", axe1_verset: "Bi-l-manni = par le reproche — la préposition bi (par, au moyen de) impose que mann soit l'instrument d'annulation, donc le comportement de reproche.", axe2_voisins: "La paire al-mann wa-l-adhā est toujours négative dans ce passage — deux comportements à éviter.", axe3_sourate: "Al-Baqarah distingue le vrai bienfait (niʿma) du mann comme reproche verbal.", axe4_coherence: "Mann comme reproche complète al-adhā comme nuisance — les deux sont des comportements négatifs.", axe5_frequence: "Dans les emplois négatifs du Coran après donner/générosité, mann désigne le reproche du bienfait." } } });

  await insertVWA(verse_id, "adhy", 10, "la nuisance envers le bénéficiaire", { sense_chosen: "la nuisance envers le bénéficiaire", concept_chosen: "Nuisance/Souffrance", concepts: { "Nuisance/Souffrance": { status: "retenu", senses: ["nuire|gêne"], proof_ctx: "Al-adhā : article défini + adhan = la nuisance comme catégorie établie.", axe1_verset: "Bi-l-manni wa-l-adhā = par le reproche et la nuisance. Al-adhā complète al-mann dans le binôme des comportements annulateurs de l'aumône.", axe2_voisins: "Adhan est apparu en V262 et V263 comme terme récurrent. En V264 avec l'article défini, c'est une catégorie comportementale bien établie.", axe3_sourate: "La nuisance (adhā) est le comportement qui transforme un acte de générosité en acte de blessure. Al-Baqarah insiste que l'acte matériel ne suffit pas — la manière compte autant que le don.", axe4_coherence: "Al-adhā avec l'article établit la nuisance comme catégorie définie, couvrant toute forme de tort envers le bénéficiaire.", axe5_frequence: "Adhan/al-adhā dans la section 261-264 apparaît 4 fois, en faisant le terme le plus répété de cette section." } } });

  await insertVWA(verse_id, "nfq", 13, "dépenser (par ostentation)", { sense_chosen: "dépenser (par ostentation)", concept_chosen: "Dépense/Distribution", concepts: { "Dépense/Distribution": { status: "retenu", senses: ["dépenser|distribuer|s'épuiser"], proof_ctx: "Yunfiqu : Form IV inaccompli 3MS de nfq. Même racine que les occurrences positives mais qualifiée par riʾāʾa l-nāsi.", axe1_verset: "Ka-lladhī yunfiqu mālahu riʾāʾa l-nāsi : la même Form IV yunfiqu décrit une dépense extérieurement identique mais intérieurement opposée à la générosité sincère.", axe2_voisins: "Le contraste yunfiqūna fī sabīli llāhi (V261, V262) vs yunfiqu riʾāʾa l-nāsi (V264) est structurant : même acte, motivations opposées, résultats opposés.", axe3_sourate: "Al-Baqarah distingue la dépense selon son intention. La même Form IV yunfiqu peut désigner la générosité la plus pure ou la plus corrompue selon les compléments.", axe4_coherence: "Yunfiqu + riʾāʾa l-nāsi = dépense dont la motivation est d'être vu. L'intention corrompt l'acte malgré son apparence identique à la générosité sincère.", axe5_frequence: "La Form IV yunfiqu dans un contexte négatif (ostentation) n'apparaît qu'ici dans la section, par contraste systématique avec ses occurrences positives." } } });

  await insertVWA(verse_id, "mwl", 14, "son bien personnel", { sense_chosen: "son bien personnel", concept_chosen: "Richesse/Biens", concepts: { "Richesse/Biens": { status: "retenu", senses: ["richesse|biens|fortune|être riche"], proof_ctx: "Mālahu : māl + suffixe 3MS = son bien (singulier). Contraste avec amwālahum (pluriel) des dépenseurs sincères.", axe1_verset: "Yunfiqu mālahu riʾāʾa l-nāsi = dépense son bien pour être vu. Le singulier mālahu contraste avec le pluriel amwālahum des sincères.", axe2_voisins: "La distinction singulier/pluriel peut refléter la différence entre une générosité complète et engagée (amwāl = ensemble des biens) vs une dépense ostentation calculée et ponctuelle (māl = bien singulier).", axe3_sourate: "Māl comme objet de la dépense ostentation souligne la neutralité matérielle des biens — c'est l'intention qui détermine la valeur.", axe4_coherence: "Mālahu + riʾāʾa l-nāsi = le bien dépensé au service du regard social, non de Dieu. L'objet est détourné de sa destination naturelle.", axe5_frequence: "Māl avec suffixe possessif singulier apparaît dans des contextes de dépense individuelle." } } });

  await insertVWA(verse_id, "ray", 15, "ostentation/désir d'être vu", { sense_chosen: "ostentation/désir d'être vu", concept_chosen: "Vision/Perception", concepts: { "Vision/Perception": { status: "probable", senses: ["voir|percevoir"], proof_ctx: "Riʾāʾa : masdar Form III de ray = se montrer, ostentation. Riʾāʾ = l'acte de chercher à être vu des autres dans ses actes.", axe1_verset: "Riʾāʾa l-nāsi = pour être vu des gens. L'ostentation est définie comme l'orientation du regard social vers soi-même au lieu de l'orientation vers Dieu.", axe2_voisins: "Riʾāʾ est l'opposé de l'ikhlāṣ (sincérité) et du fī sabīli llāhi. C'est la corruption de l'intention par le désir de reconnaissance sociale.", axe3_sourate: "Le contraste fī sabīli llāhi vs riʾāʾa l-nāsi est la dichotomie centrale : orientation vers Dieu vs orientation vers les hommes.", axe4_coherence: "Riʾāʾa directement lié au refus de foi (lā yuʾminu bi-llāhi) : l'ostentation est le symptôme de l'absence de foi authentique.", axe5_frequence: "Riʾāʾ n'apparaît que quelques fois dans le Coran (2:264, 4:38, 4:142, 8:47) mais est un concept éthique fondamental." }, "Apparition": { status: "nul", senses: ["apparaître"], proof_ctx: "Le sens d'apparition physique est secondaire ; riʾāʾ désigne ici clairement l'ostentation comme comportement intentionnel." } } });

  await insertVWA(verse_id, "nas", 17, "les gens/la société humaine", { sense_chosen: "les gens/la société humaine", concept_chosen: "Humanité/Peuple", concepts: { "Humanité/Peuple": { status: "retenu", senses: ["gens|humanité|peuple"], proof_ctx: "Al-nāsi : al-nās avec article = les gens, la société humaine. L'ostentation vise à être vu de cette société.", axe1_verset: "Riʾāʾa l-nāsi = pour être vu des gens. Al-nās désigne l'audience sociale collective dont l'approbation est recherchée.", axe2_voisins: "Al-nās vs Allāh est une opposition implicite : dépenser pour les gens (riʾāʾa) ou pour Dieu (fī sabīli llāhi). Le destinataire du regard définit la valeur de l'acte.", axe3_sourate: "Al-nās dans al-Baqarah désigne la société humaine comme système d'approbation et de réputation que le Coran invite à transcender.", axe4_coherence: "Al-nāsi + lā yuʾminu bi-llāhi : chercher le regard des hommes est lié à l'absence de foi verticale vers Dieu.", axe5_frequence: "Al-nās dans des contextes d'ostentation désigne l'audience sociale comme substitut illégitime de Dieu." } } });

  await insertVWA(verse_id, "ywm", 23, "le Jour (dernier eschatologique)", { sense_chosen: "le Jour (dernier eschatologique)", concept_chosen: "Temps/Période", concepts: { "Temps/Période": { status: "retenu", senses: ["jour|journée|temps|période"], proof_ctx: "Al-yawmi : article + yawm = le jour. Al-yawm al-ākhir est l'expression figée pour le Jour du Jugement.", axe1_verset: "Lā yuʾminu bi-llāhi wa-l-yawmi l-ākhiri : la foi en Dieu et en le Jour Dernier est le binôme de base de la foi islamique. Sans foi en ce Jour, toute générosité est nécessairement mondaine.", axe2_voisins: "La paire Allāh + al-yawm al-ākhir est récurrente dans al-Baqarah comme définition minimale de la foi.", axe3_sourate: "Al-yawm al-ākhir oriente toutes les actions vers une rétribution future. Sans cette foi, l'approbation sociale immédiate devient la seule récompense recherchée.", axe4_coherence: "L'absence de foi au Jour Dernier explique la générosité ostentation : sans horizon eschatologique, seule l'approbation sociale immédiate compte.", axe5_frequence: "Al-yawm al-ākhir apparaît environ 26 fois dans le Coran comme expression technique du Jour du Jugement." } } });

  await insertVWA(verse_id, "axr", 24, "dernier/postérieur", { sense_chosen: "dernier/postérieur", concept_chosen: "Postériorité/Retard", concepts: { "Postériorité/Retard": { status: "retenu", senses: ["retarder|reporter|dernier|l'au-delà"], proof_ctx: "Al-ākhiri : adjectif de axr = postérieur, dernier. Al-yawm al-ākhir = le Jour le plus tardif.", axe1_verset: "Al-yawm al-ākhir = le Jour Dernier, le jour qui clôt tous les jours. Ākhir exprime la postériorité absolue — après ce jour il n'y en a plus.", axe2_voisins: "La dualité al-ākhira / al-dunyā structure la morale coranique. Al-yawm al-ākhir est le point de bascule entre les deux.", axe3_sourate: "La foi au yawm al-ākhir dans al-Baqarah est la condition de l'orientation eschatologique des actes. Sans elle, les actes restent prisonniers du présent mondain.", axe4_coherence: "Ākhir (dernier) dans al-yawm al-ākhir est la qualification eschatologique standard dans le Coran.", axe5_frequence: "Ākhir dans des contextes eschatologiques apparaît des dizaines de fois dans le Coran." } } });

